s.__DUMI_FM__=globalThis.__DUMI_FM__||{},globalThis.__DUMI_TOC__=globalThis.__DUMI_TOC__||{},globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/table-scroll-ghost.zh-CN.md"]={title:"Table 的滚动偏啦",toc:"menu",filename:"docs/blog/table-scroll-ghost.zh-CN.md",lastUpdated:1784864311e3,date:"2026-07-08T00:00:00.000Z",author:"zombieJ",__autoDescription:!0,description:"最近我们遇到了一个 Table 横向滚动错位的问题。在虚拟滚动场景下，用户拖动横向滚动条，表体已经滚动到正确位置，但是表头偶尔会停在旧的位置。尤其是在滚回最左侧时，表体已经是 0，表头却停在中间位置。"},globalThis.__DUMI_TOC__["/home/runner/work/ant-design/ant-design/docs/blog/table-scroll-ghost.zh-CN.md"]=[{id:"先看滚动同步",depth:3,title:"先看滚动同步"},{id:"看起来像锁",depth:3,title:"看起来像锁"},{id:"日志对不上",depth:3,title:"日志对不上"},{id:"延迟同步",depth:3,title:"延迟同步"},{id:"修复",depth:3,title:"修复"},{id:"总结",depth:3,title:"总结"}];let G=globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/table-scroll-ghost.zh-CN.md"],W=globalThis.__DUMI_TOC__["/home/runner/work/ant-design/ant-design/docs/blog/table-scroll-ghost.zh-CN.md"];globalThis.__DUMI_FM__=globalThis.__DUMI_FM__||{},globalThis.__DUMI_TOC__=globalThis.__DUMI_TOC__||{},globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.en-US.md"]={title:"How to Grow as a Collaborator",toc:"menu",filename:"docs/blog/to-be-collaborator.en-US.md",lastUpdated:1784864311e3,date:"2022-12-22T00:00:00.000Z",author:"heiyu4585",zhihu_url:"https://zhuanlan.zhihu.com/p/639265896",yuque_url:"https://www.yuque.com/ant-design/ant-design/as5hro5edxcslweh",__autoDescription:!0,description:"Hello everyone, I am heiyu. About Ant Design, I believe everyone is very familiar with it. Before I contributed to Ant Design, I have used Ant Design in many background management system projects at work. The biggest feeling for me is that it is easy to use, beautiful, simple and stable. Now that the v5 version has been released, I strongly recommend everyone to try it. I am also fortunate to have developed the v5 version of the Tour component and App component, as well as some other maintenance work. Let me share with you the PR process of Ant Design, hoping to provide a reference for who are interested in building together for the community."},globalThis.__DUMI_TOC__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.en-US.md"]=[{id:"read-related-articles-to-familiarize-yourself-with-related-concepts",depth:3,title:"Read related articles to familiarize yourself with related concepts"},{id:"pull-ant-design-code-to-local",depth:2,title:"Pull Ant Design code to local"},{id:"1-fork-project",depth:3,title:"1. Fork project"},{id:"2-add-remote-branch-address",depth:3,title:"2. Add remote branch address"},{id:"3-create-a-new-fix-branch-on-github",depth:3,title:"3. Create a new fix branch on github"},{id:"4-pull-the-new-branch-locally",depth:3,title:"4. Pull the new branch locally"},{id:"find-the-issue-on-the-ant-design-issue-page-and-analyze-the-selection",depth:2,title:"Find the issue on the Ant Design issue page and analyze the selection"},{id:"development-process",depth:2,title:"Development Process"},{id:"run-test-cases-and-specification-checks",depth:2,title:"Run test cases and specification checks"},{id:"merge-changes",depth:2,title:"Merge changes"},{id:"submit-a-pull-request",depth:2,title:"Submit a Pull Request"},{id:"accept-the-maintainers-review-and-modify-it-and-wait-for-the-maintainer-to-merge-after-passing-the-test",depth:2,title:"Accept the maintainer's review and modify it, and wait for the maintainer to merge after passing the test"},{id:"common-errors",depth:2,title:"Common errors"},{id:"to-be-collaborator",depth:2,title:"To be collaborator"},{id:"dont-be-afraid-to-make-mistakes-do-it-bravely-everyone-is-welcome-in-the-open-source-world",depth:2,title:"Don't be afraid to make mistakes, do it bravely, everyone is welcome in the open source world."},{id:"related-resources",depth:2,title:"Related resources"}];let H=globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.en-US.md"],V=globalThis.__DUMI_TOC__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.en-US.md"];globalThis.__DUMI_FM__=globalThis.__DUMI_FM__||{},globalThis.__DUMI_TOC__=globalThis.__DUMI_TOC__||{},globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.zh-CN.md"]={title:"如何成长为 Collaborator",toc:"menu",filename:"docs/blog/to-be-collaborator.zh-CN.md",lastUpdated:1784864311e3,date:"2022-12-22T00:00:00.000Z",author:"heiyu4585",zhihu_url:"https://zhuanlan.zhihu.com/p/639265896",yuque_url:"https://www.yuque.com/ant-design/ant-design/as5hro5edxcslweh",__autoDescription:!0,description:"大家好，我是黑雨。关于 Ant Design，相信大家都非常熟悉，我在很多后台管理系统项目使用过 Ant Design，给我最大的感觉就是好用、好看、简单、稳定。现在 v5 版本已经发布，强烈推荐大家试使用，我也有幸开发了 v5 版本的 Tour 组件和 App 组件，以及一些其他维护工作。下面给大家分享一下 Ant Design 的 PR 流程，希望能给有兴趣为社区共建的同学提供一份参考。"},globalThis.__DUMI_TOC__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.zh-CN.md"]=[{id:"一-阅读相关文章熟悉相关概念",depth:2,title:"一. 阅读相关文章熟悉相关概念"},{id:"二-拉取-ant-design-代码到本地",depth:2,title:"二. 拉取 Ant Design 代码到本地"},{id:"1-fork-项目",depth:3,title:"1. Fork 项目"},{id:"2-添加远端分支地址",depth:3,title:"2. 添加远端分支地址"},{id:"3-在-github-上创建新-fix-分支",depth:3,title:"3. 在 github 上创建新 fix 分支"},{id:"4-在本地拉取新分支",depth:3,title:"4. 在本地拉取新分支"},{id:"三-在ant-design-的-issue页找到-issue-并分析选择",depth:2,title:"三. 在Ant Design 的 issue页找到 issue 并分析选择"},{id:"四-开发流程",depth:2,title:"四. 开发流程"},{id:"五-运行测试用例及规范检查",depth:2,title:"五. 运行测试用例及规范检查"},{id:"六-合并修改",depth:2,title:"六. 合并修改"},{id:"七-提交-pull-request",depth:2,title:"七. 提交 Pull Request"},{id:"八-接受维护者的-review-并修改合格后等待维护者-merge",depth:2,title:"八. 接受维护者的 review 并修改，合格后等待维护者 merge"},{id:"九-常见错误",depth:2,title:"九. 常见错误"},{id:"十-成为-collaborator",depth:2,title:"十. 成为 Collaborator"},{id:"不要怕犯错误勇敢地去做开源世界欢迎大家",depth:2,title:"不要怕犯错误，勇敢地去做，开源世界欢迎大家。"},{id:"相关资源",depth:2,title:"相关资源"}];let J=globalThis.__DUMI_FM__["/home/runner/work/ant-design/ant-design/docs/blog/to-be-collaborator.zh-CN.md"],Y=globa